import{_ as s,o as e,c as n,a2 as p}from"./chunks/framework.C24VBsJ9.js";const u=JSON.parse('{"title":"为什么需要完整镜像 - 别再手工拼系统了","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/flash/04_why_full_image.md","filePath":"tutorial/flash/04_why_full_image.md","lastUpdated":1780980021000}'),i={name:"tutorial/flash/04_why_full_image.md"};function l(t,a,o,d,r,c){return e(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="为什么需要完整镜像-别再手工拼系统了" tabindex="-1">为什么需要完整镜像 - 别再手工拼系统了 <a class="header-anchor" href="#为什么需要完整镜像-别再手工拼系统了" aria-label="Permalink to &quot;为什么需要完整镜像 - 别再手工拼系统了&quot;">​</a></h1><h2 id="前言-我们为什么又要折腾一个-img" tabindex="-1">前言：我们为什么又要折腾一个 <code>.img</code> <a class="header-anchor" href="#前言-我们为什么又要折腾一个-img" aria-label="Permalink to &quot;前言：我们为什么又要折腾一个 \`.img\`&quot;">​</a></h2><p>说实话，刚开始做板子启动的时候，我其实并不觉得“完整镜像”有什么必要。</p><p>U-Boot 有了，内核有了，设备树也有了，rootfs 目录也在那儿。那不就是把 <code>u-boot-dtb.imx</code> 写到固定偏移，再把 <code>zImage</code> 和 <code>.dtb</code> 拷到 boot 分区，最后把 rootfs 拷到 root 分区吗？</p><p>听起来很简单，对吧。</p><p>问题是，这种“手工拼系统”的方式只要步骤一多，就会开始露出它最麻烦的一面：每一步都看起来合理，但任何一步做错，最后表现出来都可能只是板子起不来。</p><p>你可能会遇到这些情况：</p><ul><li>U-Boot 烧进去了，但分区表没有按预期创建</li><li><code>zImage</code> 和 DTB 拷过去了，但 rootfs 没有同步完整</li><li>SD 卡镜像用了 eMMC 的 root 参数</li><li>只更新了 boot 分区，却忘了 raw U-Boot 还停留在旧版本</li><li>复制文件的时候看起来成功了，实际权限、软链接或设备节点已经变味</li></ul><p>这些问题排查起来很烦，因为它们不是“编译失败”这种明确错误，而是启动链条中某个环节悄悄不对。完整镜像要解决的，就是这个问题。</p><h2 id="我们现在手里有什么" tabindex="-1">我们现在手里有什么 <a class="header-anchor" href="#我们现在手里有什么" aria-label="Permalink to &quot;我们现在手里有什么&quot;">​</a></h2><p>先把构建产物摆出来看一眼。一次 release 构建完成后，<code>out/release-latest/</code> 下面大概是这个样子：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/</span></span>
<span class="line"><span>├── uboot/</span></span>
<span class="line"><span>│   └── u-boot-dtb.imx</span></span>
<span class="line"><span>├── linux/</span></span>
<span class="line"><span>│   └── arch/arm/boot/</span></span>
<span class="line"><span>│       ├── zImage</span></span>
<span class="line"><span>│       └── dts/nxp/imx/imx6ull-aes.dtb</span></span>
<span class="line"><span>└── rootfs/</span></span>
<span class="line"><span>    ├── bin/</span></span>
<span class="line"><span>    ├── etc/</span></span>
<span class="line"><span>    ├── lib/</span></span>
<span class="line"><span>    └── ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>这几个东西都很重要，但它们还只是“零件”。</p><p><code>u-boot-dtb.imx</code> 是启动第一个阶段要用的东西；<code>zImage</code> 是内核；<code>.dtb</code> 告诉内核板子长什么样；<code>rootfs/</code> 是 Linux 起来之后真正进入的用户空间。</p><p>这些零件单独看都没问题，但板子不会因为你把零件放在一个目录里就自动启动。板子需要的是一块存储设备上的完整布局。</p><p>也就是说，我们真正想要的是这样一个东西：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一整块“假想的 SD/eMMC”</span></span>
<span class="line"><span>├── 开头的 raw U-Boot 区域</span></span>
<span class="line"><span>├── 分区表</span></span>
<span class="line"><span>├── boot 分区</span></span>
<span class="line"><span>│   ├── zImage</span></span>
<span class="line"><span>│   └── imx6ull-aes.dtb</span></span>
<span class="line"><span>└── rootfs 分区</span></span>
<span class="line"><span>    └── 完整根文件系统</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这个“假想的 SD/eMMC”就是 <code>.img</code> 文件。</p><h2 id="手工拷贝为什么不够稳" tabindex="-1">手工拷贝为什么不够稳 <a class="header-anchor" href="#手工拷贝为什么不够稳" aria-label="Permalink to &quot;手工拷贝为什么不够稳&quot;">​</a></h2><p>手工拷贝最大的问题不是它不能用，而是它太依赖“人脑状态”。</p><p>比如你今天只改了设备树，很自然会想着：“那我只拷一个 DTB 就行。”这在开发阶段没问题。可过两天你又改了 U-Boot 默认环境，再过两天 rootfs overlay 也变了。等到要交付或者复现问题的时候，你很可能已经忘了哪一步是最新的。</p><p>更麻烦的是，手工流程里有些东西不是文件复制能覆盖的。</p><p>U-Boot 就是典型例子。它不是 boot 分区里的一个普通文件，而是写在存储设备前面某个 raw 偏移上的启动镜像。你把 <code>zImage</code> 拷得再漂亮，也不会顺便更新 raw U-Boot。</p><p>分区表也是一样。你在文件管理器里能看到 boot 分区和 rootfs 分区，不代表分区布局就是项目当前期望的布局。</p><p>所以完整镜像的价值不只是“少敲几条命令”，而是把整套启动状态固化下来。</p><h2 id="完整镜像到底固定了什么" tabindex="-1">完整镜像到底固定了什么 <a class="header-anchor" href="#完整镜像到底固定了什么" aria-label="Permalink to &quot;完整镜像到底固定了什么&quot;">​</a></h2><p><code>build_imx6ull_image.sh</code> 生成的镜像，本质上把四件事固定在一个文件里。</p><p>第一件事是 U-Boot 的位置。脚本会把：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/uboot/u-boot-dtb.imx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>写到镜像文件的 1 KiB 偏移处。这个位置不是某个分区内部，而是 raw disk 区域。</p><p>第二件事是分区表。镜像里会有一个 MBR 分区表，告诉系统哪里是 boot 分区，哪里是 rootfs 分区。</p><p>第三件事是 boot 分区内容。这里面会放：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/zImage</span></span>
<span class="line"><span>/imx6ull-aes.dtb</span></span>
<span class="line"><span>/boot.cmd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>脚本也会额外放一份到 <code>/boot/</code> 目录，方便后续兼容不同启动习惯。</p><p>第四件事是 rootfs。<code>out/release-latest/rootfs/</code> 会被打包成第二个 ext4 分区。Linux 启动后挂载的根目录，就是这里。</p><p>这样一来，最终产物就很明确：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/images/imx6ull-aes-emmc.img</span></span>
<span class="line"><span>out/release-latest/images/imx6ull-aes-sd.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>你拿到这个文件，不需要再猜“这个镜像是不是少了 rootfs”“这个 U-Boot 是不是旧的”。它就是一整块盘。</p><h2 id="sd-和-emmc-为什么不能混着来" tabindex="-1">SD 和 eMMC 为什么不能混着来 <a class="header-anchor" href="#sd-和-emmc-为什么不能混着来" aria-label="Permalink to &quot;SD 和 eMMC 为什么不能混着来&quot;">​</a></h2><p>这里有个很容易踩的坑：SD 镜像和 eMMC 镜像看起来非常像，但它们不能随便混用。</p><p>原因不在文件系统内容，而在启动参数。</p><p>在当前项目约定里：</p><table tabindex="0"><thead><tr><th>目标介质</th><th>U-Boot 里看到的设备</th><th>Linux 里的 root 分区</th></tr></thead><tbody><tr><td>SD</td><td><code>mmc 0</code></td><td><code>/dev/mmcblk0p2</code></td></tr><tr><td>eMMC</td><td><code>mmc 1</code></td><td><code>/dev/mmcblk1p2</code></td></tr></tbody></table><p>如果你用 eMMC 镜像去走 SD 启动，U-Boot 命令里可能会去 <code>mmc 1:1</code> 加载内核，Linux 也会去找 <code>/dev/mmcblk1p2</code>。如果板子当前实际从 SD 起，那这个 root 设备很可能根本不是你想要的那个。</p><p>这类问题在串口里通常会变成一句很朴素的报错：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VFS: Cannot open root device</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>所以脚本提供了：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--boot-media</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sd</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--boot-media</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">emmc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>它不只是改了输出文件名。它会影响 <code>boot.cmd</code>、manifest 里的启动命令，以及 Linux 的 <code>root=</code> 参数。</p><h2 id="完整镜像和-nfs-不是一回事" tabindex="-1">完整镜像和 NFS 不是一回事 <a class="header-anchor" href="#完整镜像和-nfs-不是一回事" aria-label="Permalink to &quot;完整镜像和 NFS 不是一回事&quot;">​</a></h2><p>这里还要顺手澄清一下：完整镜像不是为了替代 NFS。</p><p>NFS 在开发阶段非常舒服。你改主机上的 rootfs，板子重启后就能看到变化，不需要反复烧卡。做驱动调试、应用调试、rootfs 配置验证时，NFS 仍然是很重要的工具。</p><p>完整镜像更适合这些场景：</p><ul><li>第一次把板子启动起来</li><li>做 SD/eMMC 的完整启动验证</li><li>给别人一个可复现的系统产物</li><li>release 构建后确认交付物完整</li><li>排查“到底是文件没拷对，还是启动参数不对”</li></ul><p>你可以把它理解成两种工作模式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开发迭代：TFTP + NFS</span></span>
<span class="line"><span>交付验证：完整 SD/eMMC 镜像</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>一个负责快，一个负责稳。</p><h2 id="我们接下来要看什么" tabindex="-1">我们接下来要看什么 <a class="header-anchor" href="#我们接下来要看什么" aria-label="Permalink to &quot;我们接下来要看什么&quot;">​</a></h2><p>这一章先解决“为什么要做完整镜像”的问题。下一章我们拆开这个 <code>.img</code>，看看里面每个偏移、每个分区为什么这样安排。</p><p>你会发现，脚本并没有做什么神秘的事情。它只是把我们原来手工做的步骤，变成了一套固定、可检查、可复现的流程。</p><p><strong>下一步：</strong> 继续阅读 <a href="./05_image_layout_design">05_image_layout_design.md</a>，看完整镜像内部到底长什么样。</p>`,61)])])}const m=s(i,[["render",l]]);export{u as __pageData,m as default};
